INSERT INTO `articles` (`id_article`, `title`, `intro`, `description`, `note`, `critic`, `opinion`, `banner_img`, `card_img`, `date_add`, `id_author`) VALUES
(1, 'Cyberpunk 2077', 'Plongez au cœur de Night City, une dystopie futuriste fascinante et impitoyable où la frontière entre l’humanité et la technologie cybernétique s’est totalement estompée au profit des corporations.', 'Cyberpunk 2077 invite le joueur à incarner V, un mercenaire à la recherche d’un implant unique qui détient la clé de l’immortalité. L’aventure se déroule à Night City, une mégalopole tentaculaire et verticale gangrenée par les inégalités, les guerres de gangs et l’influence omniprésente des mégacorporations. Le jeu fusionne magistralement une vue à la première personne immersive, une narration dynamique à choix multiples et une personnalisation poussée (compétences, implants cybernétiques, style vestimentaire). Chaque quartier de la ville possède sa propre identité visuelle, sociale et sonore, renforçant le sentiment de gigantisme. Côté gameplay, les affrontements alternent de manière fluide entre fusillades nerveuses, infiltration tactique, piratage à distance des systèmes de sécurité et affrontements au corps à corps à l’aide de lames de bras.', 9.0, 'Après un lancement technique catastrophique entré dans l’histoire de l’industrie, Cyberpunk 2077 a connu une rédemption spectaculaire. Grâce au déploiement de nombreuses mises à jour majeures et de l’extension Phantom Liberty, le titre est devenu l’expérience stable, dense et cohérente qu’il aurait toujours dû être. La direction artistique est un véritable tour de force visuel, sublimée par des technologies de pointe comme le ray tracing. L’écriture globale s’avère d’une maturité rare, portée par des personnages secondaires d’une profondeur exceptionnelle tels que Johnny Silverhand, Panam Palmer ou Judy Alvarez, dont les arcs narratifs restent gravés en mémoire. Si l’on peut encore pester contre une physique des véhicules perfectible et quelques promesses initiales non tenues sur l’intelligence artificielle des passants, l’immersion globale atteinte dans ce RPG moderne est tout simplement prodigieuse.', 'J’ai énormément apprécié l’univers et l’ambiance générale. Night City est fascinante à explorer et certaines quêtes secondaires sont excellentes. Même si le jeu n’est pas parfait, il reste extrêmement prenant.', 'cyberpunk_banner.jpg', 'cyberpunk-2077-card-1780689902.jpg', '2026-05-04 15:43:58', 1),
(2, 'The Witcher 3', 'Incarnez Geralt de Riv, un tueur de monstres cynique et désabusé, dans une quête désespérée pour retrouver sa fille adoptive au milieu d’un continent déchiré par la guerre.', 'The Witcher 3: Wild Hunt propulse le joueur dans un monde ouvert de fantasy sombre d’une richesse inouïe. Le joueur y suit les traces de Geralt de Riv, un Sorceleur génétiquement modifié, chargé de retrouver Ciri, une jeune femme dotée de pouvoirs temporels poursuivie par une cavalerie spectrale légendaire. Le jeu brise les codes du genre en proposing un monde interconnecté et vivant, où la politique, le racisme, la misère et le folklore slave se mélangent. Le gameplay alterne entre l’exploration à cheval ou en bateau, la traque rigoureuse de monstres via les sens développés du Sorceleur, et des combats dynamiques combinant deux types d’épées, des potions alchimiques préparées à l’avance et des signes magiques rudimentaires.', 9.5, 'CD Projekt RED a signé avec ce troisième opus un chef-d’œuvre absolu qui a redéfini les standards de l’écriture dans le jeu vidéo en monde ouvert. La plus grande prouesse du titre réside dans le traitement de ses quêtes secondaires : aucune n’est générique, chacune possède son propre arc narratif, ses rebondissements et des dilemmes moraux complexes aux conséquences imprévisibles et parfois tragiques à long terme. La bande-son, aux accents slaves et tribaux, est d’une puissance immersive inégalée. Certes, avec le recul, le système de combat montre ses limites par une certaine rigidité et une caméra parfois capricieuse, et l’inventaire initial manquait d’ergonomie. Pourtant, la profondeur de l’univers et l’incroyable mélancolie qui se dégage des paysages de Velen ou de Skellige en font une référence incontournable de l’histoire du RPG.', 'C’est probablement un des jeux qui m’a le plus marqué. Les personnages sont incroyablement bien écrits et l’univers donne envie d’explorer chaque recoin.', 'witcher_banner.jpg', 'witcher_card.jpg', '2026-05-03 15:43:58', 1),
(3, 'Elden Ring', 'Une réinvention magistrale du monde ouvert par les créateurs de Dark Souls, où la liberté d’exploration absolue se mêle à une exigence de combat impitoyable.', 'Elden Ring transpose la formule exigeante et mystérieuse des « Souls-like » au sein d’un gigantesque monde ouvert baptisé les Terres Intermédiaires. Conçu en collaboration avec l’auteur George R.R. Martin pour le lore, le jeu invite un Sans-éclat à restaurer le Cercle d’Elden pour devenir le Seigneur d’Elden. Le joueur est totalement libre de sa progression dès les premières minutes, sans marqueurs omniprésents pour lui dicter sa route. L’univers regorge de donjons cachés, de catacombes labyrinthiques, de boss optionnels colossaux et de panoramas vertigineux. Pour faire face à la difficulté, le gameplay enrichit ses mécaniques traditionnelles avec l’introduction d’une monture agile (Torrente), d’un bouton de saut pour la verticalité, de la possibilité d’invoquer des esprits alliés et d’un système de craft.', 9.0, 'FromSoftware a réussi le pari fou de fusionner la liberté totale d’un Zelda: Breath of the Wild avec la structure rigoureuse et gratifiante de ses propres créations. Le level design est un chef-d’œuvre absolu de verticalité et de direction artistique, capable de couper le souffle du joueur au détour d’un simple ascenseur menant à une cité souterraine. Le sentiment de progression est exceptionnel : chaque mort est une leçon, et la curiosité est constamment récompensée par une nouvelle arme ou un sortilège majeur. On regrettera toutefois quelques redites de boss dans les donjons mineurs vers la fin du jeu, ainsi qu’une optimisation technique parfois chancelante sur certaines plateformes (notamment des chutes de framerate). Malgré cela, l’expérience globale est une date clé pour l’industrie du jeu vidéo.', 'Chaque exploration réserve une surprise. La sensation de découvrir un nouveau lieu ou de vaincre un boss difficile est incroyablement gratifiante.', 'elden-ring-banner-1780691430.jpg', 'elden-ring-card-1780691430.jpg', '2026-03-16 16:43:58', 1),
(4, 'Red Dead Redemption 2', 'Vivez le crépuscule de l’era de l’Ouest sauvage à travers le destin tragique d’un gang de hors-la-loi traqués par la modernité naissante du XXe siècle.', 'Red Dead Redemption 2 est une préquelle qui retrace la longue et douloureuse déchéance du gang de Dutch van der Linde en 1899, vue à travers les yeux d’Arthur Morgan, un bras droit loyal mais assailli par les doutes. Le jeu se distingue par un photoréalisme bluffant et un souci du détail presque obsessionnel. Le monde ouvert est un écosystème vivant autonome : la faune réagit de manière réaliste, la météo influence l’état physique du héros, et chaque PNJ possède un emploi du temps complet. Le gameplay fait la part belle à la simulation de vie (chasser pour nourrir le camp, entretenir ses armes, brosser son cheval) tout en proposant des phases d’action intenses à base de fusillades utilisant le célèbre système de visée ralentie « Dead Eye ».', 9.7, 'Rockstar Games livre ici une œuvre monumentale, un véritable jalon technique et narratif pour le média. La mise en scène est d’un niveau cinématographique rarement égalé, portée par des performances d’acteurs fantastiques, en particulier celle de Roger Clark dans le rôle d’un Arthur Morgan complexe et profondément humain. La physique des corps, la gestion de la lumière et la splendeur des environnements naturels forcent le respect. Le jeu divise cependant par son parti pris d’extrême lenteur et sa lourdeur volontaire dans les mouvements, qui privilégient le réalisme brut au détriment de l’immédiateté ludique. De plus, la structure des missions principales reste très rigide et dirigiste par rapport à la liberté offerte en dehors. C’est une fresque interactive exigeante, mais d’une beauté émotionnelle bouleversante.', 'L’immersion est incroyable. On a réellement l’impression de vivre dans cet univers et pas simplement de jouer dans un décor.', 'red-dead-redemption-2-banner-1780691289.jpg', 'red-dead-redemption-2-card-1780691289.jpg', '2026-04-21 15:43:58', 1),
(5, 'Hogwarts Legacy', 'Réalisez votre rêve d’enfant en franchissant les portes de Poudlard au XIXe siècle pour y mener une vie d’étudiant sorcier pleine de mystères et de magie.', 'Hogwarts Legacy: L’Héritage de Poudlard est un RPG d’action-aventure qui place le joueur dans la peau d’un élève de cinquième année possédant une connexion rare avec une magie ancienne et oubliée. Situé bien avant les événements des livres et des films, le jeu permet d’explorer de fond en comble le château de Poudlard, le village de Pré-au-Lard ainsi que les vastes contrées environnantes. Le joueur choisit sa maison, assiste à des cours de potions, de botanique ou de défense contre les forces du mal, et apprend une grande variété de sorts. Le système de combat à la baguette est étonnamment dynamique, reposant sur des enchaînements de combos magiques, des contres précis et l’utilisation de l’environnement pour briser les boucliers ennemis.', 7.5, 'Le studio Avalanche Software a brillamment relevé le défi du fan-service de haut vol. La modélisation de Poudlard est un chef-d’œuvre de fidélité et d’architecture, regorgeant de détails cachés, de tableaux mouvants et de passages secrets qui émerveilleront n’importe quel amateur de la franchise. Les vols en balai ou à dos d’hippogriffe offrent des sensations de liberté exquises. Malheureusement, une fois sorti de l’enceinte scolaire, le jeu souffre des travers classiques des mondes ouverts modernes : une prolifération d’activités annexes répétitives (comme les énigmes de Merlin), un scénario principal assez conventionnel et un manque d’impact des choix moraux sur la vie de l’élève. Les mécaniques RPG manquent de profondeur, mais le plaisir de lancer un « Lumos » ou un « Confringo » dans une forêt interdite reste immense.', 'Explorer Poudlard était exactement ce que j’attendais depuis des années. Même avec ses défauts, le jeu reste très plaisant pour les fans de l’univers.', 'hogwarts-legacy-banner-1780690660.jpg', 'hogwarts-legacy-card-1780690660.jpg', '2026-04-25 15:43:58', 1),
(6, 'Assassin’s Creed Valhalla', 'Prenez la tête d’un clan de redoutables guerriers vikings et partez conquérir les royaumes divisés de l’Angleterre médiévale pour y bâtir votre colonie.', 'Assassin’s Creed Valhalla invite le joueur à incarner Eivor, une légende viking en quête de gloire et de terres pour son peuple. Fuyant la Norvège devenue trop étroite, le clan s’installe en Angleterre au IXe siècle, une époque de chaos politique. Le cœur du jeu repose sur la conquête territoriale par le biais d’alliances stratégiques, de raids brutaux de monastères en drakkar pour piller des ressources, et du développement progressif de la colonie de Ravensthorpe. Le système de combat a été revu pour refléter la violence de l’époque, permettant le maniement de deux armes simultanément (comme deux haches ou un bouclier et une épée), l’exécution de décapitations sanglantes et la gestion d’une jauge d’endurance.', 7.8, 'Ubisoft livre un terrain de jeu gargantuesque à la direction artistique soignée, offrant des paysages automnaux anglais magnifiques et une Norvège enneigée saisissante. La structure narrative découpée en sagas régionales tente d’imiter les séries télévisées historiques avec un certain succès. De plus, la réduction des quêtes annexes au profit de « mystères » spontanés est une excellente idée. Cependant, Valhalla souffre cruellement de sa propre démesure : le jeu est beaucoup trop long (comptez plus de 80 heures pour voir le bout de l’intrigue principale), ce qui engendre une lassitude inévitable et dilue le fil rouge lié aux Assassins. On note également de nombreux bugs d’animation et d’intelligence artificielle qui ternissent l’expérience. Un très bon jeu de vikings, mais un Assassin’s Creed parfois trop générique.', 'J’ai beaucoup aimé l’ambiance nordique et certaines régions sont magnifiques à parcourir. Le jeu aurait simplement gagné à être un peu plus condensé.', 'assassin-s-creed-valhalla-banner-1780690228.jpg', 'assassin-s-creed-valhalla-card-1780690228.jpg', '2026-05-01 15:43:58', 1),
(7, 'Zelda Breath of the Wild', 'Une révolution historique du jeu d’aventure qui brise toutes les conventions pour offrir une ode absolue à la liberté et à la curiosité humaine.', 'The Legend of Zelda: Breath of the Wild réveille un Link amnésique après un sommeil d’un siècle, découvrant un royaume d’Hyrule en ruines sous l’emprise du Fléau Ganon. Ce titre se détache radicalement de ses prédécesseurs en éliminant toute linéarité. Le monde extérieur devient le gameplay lui-même. Grâce à une jauge d’endurance, Link peut escalader absolument toutes les surfaces visibles et planer depuis les sommets à l’aide d’une paravoile. Le jeu repose sur un moteur physique et chimique révolutionnaire : le feu propage les incendies selon le vent, la foudre est attirée par les armures métalliques, et le froid exige des vêtements chauds ou de la cuisine adaptée. Les armes ont une durabilité limitée, forçant le joueur à renouveler constamment son arsenal.', 9.8, 'Nintendo a tout simplement redéfini les contours du jeu en monde ouvert. Au lieu de guider le joueur par le nez avec une liste de tâches fastidieuse, Breath of the Wild fait confiance à son intelligence et stimule son sens de l’observation (une fumée au loin, une montagne étrange). La physique du jeu permet de résoudre les énigmes des 120 Sanctuaires de mille manières différentes, encourageant l’expérimentation joyeuse. On peut émettre quelques réserves sur la fragilité excessive des armes au début de l’aventure, le manque de variété des boss majeurs (les déclinaisons de l’Ombre de Ganon) et l’absence de véritables grands donjons thématiques traditionnels. Néanmoins, l’immense sentiment de solitude, la poésie de la bande-son minimaliste au piano et le souffle épique de l’aventure en font un chef-d’œuvre intemporel.', 'C’est l’un des rares jeux où je me suis perdu volontairement pendant des heures juste pour explorer.', 'zelda-breath-of-the-wild-banner-1780690381.jpg', 'zelda-breath-of-the-wild-card-1780690381.jpg', '2026-04-30 15:43:58', 1),
(8, 'God of War Ragnarok', 'Suivez le voyage poignant de Kratos et d’Atreus à travers les Neuf Royaumes alors que prophéties destructrices et dieux nordiques menacent leur cellule familiale.', 'God of War Ragnarok fait suite au reboot acclamé de 2018. Le Fimbulwinter, l’hiver rigoureux qui annonce la fin du monde, s’est abattu sur Midgard. Kratos et son fils Atreus, désormais adolescent, doivent parcourir les Neuf Royaumes pour trouver des réponses alors que les forces d’Asgard se préparent à une guerre totale. Le gameplay conserve sa caméra à l’épaule sans aucun plan-séquence de coupure et magnifie ses combats viscéraux. La hache Leviathan et les Lames du Chaos sont de retour, enrichies par de nouvelles options de verticalité, des boucliers aux propriétés variées et la possibilité de contrôler directement Atreus lors de certains segments narratifs spécifiques, offrant un style de combat à l’arc mais agile.', 9.6, 'Le studio Santa Monica signe une suite d’une maîtrise technique et narrative absolue, qui clôt l’arc nordique avec brio. L’évolution des relations humaines est le cœur vibrant du jeu : l’écriture fine explore les thèmes du deuil, de la parentalité, du destin et du pardon avec une justesse bouleversante. Visuellement, le jeu est une claque de chaque instant, affichant des environnements variés, de la jungle luxuriante de Vanaheim aux mines naines de Svartalfheim. Les combats ont gagné en nervosité et le bestiaire est bien plus diversifié que dans le précédent opus. Quelques longueurs narratives se font ressentir au milieu de l’aventure (notamment le segment d’Ironwood) et les compagnons ont un peu trop tendance à souffler la solution des énigmes, mais l’aventure reste un sommet de l’action-aventure.', 'Les relations entre les personnages sont excellentes et certaines scènes sont vraiment marquantes.', 'god-of-war-ragnarok-banner-1780690572.jpg', 'god-of-war-ragnarok-card-1780690572.jpg', '2026-04-28 15:43:58', 1),
(9, 'Final Fantasy XVI', 'Une tragédie médiévale-fantasy sombre et mature, où la vengeance d’un homme se mêle à des guerres dantesques entre colosses divins.', 'Final Fantasy XVI marque un tournant radical pour la franchise légendaire en adoptant un ton résolument inspiré de la Dark Fantasy occidentale (façon Game of Thrones). Le joueur suit le destin tragique de Clive Rosfield, le fils aîné de l’archiduché de Rosalia, sur une période de plusieurs décennies marquée par la trahison, les complots géopolitiques et l’extinction progressive de la magie dans le monde de Valisthéa. Abandonnant totalement le tour par tour, le système de combat est un Action-RPG pur et frénétique conçu par le directeur des combats de Devil May Cry 5. Clive peut alterner à la volée entre les compétences magiques de différents Primordiaux (les invocations) pour terrasser ses ennemis dans des ballets de combos spectaculaires.', 8.2, 'Square Enix livre une œuvre à la mise en scène proprement ahurissante, portée par des affrontements entre Primordiaux qui comptent parmi les moments les plus spectaculaires et dantesques de l’histoire du jeu vidéo. La bande-son de Masayoshi Soken est magistrale et l’histoire tient en haleine grâce à une narration adulte sans concessions. Cependant, ce virage vers l’action pure laisse de côté de nombreuses mécaniques chères aux amateurs de RPG : la gestion de l’équipement est extrêmement superficielle, l’exploration des zones semi-ouvertes est décevante, et l’artisanat s’avère anecdotique. De plus, le rythme souffre de montagnes russes, plombé par des quêtes secondaires au design archaïque de type « fedex » entre deux moments d’anthologie. Un excellent jeu d’action épique, mais un RPG timide.', 'Les affrontements contre les Primordiaux sont impressionnants et donnent une vraie sensation d’échelle.', 'final-fantasy-xvi-banner-1780690775.jpg', 'final-fantasy-xvi-card-1780690775.jpg', '2026-04-22 15:43:58', 1),
(10, 'Spider-Man 2', 'Deux Tisseurs pour le prix d’un dans une New York transfigurée, faisant face à la férocité de Kraven le Chasseur et au cauchemar du symbiote Venom.', 'Marvel’s Spider-Man 2 réunit Peter Parker et Miles Morales pour défendre une version étendue de New York, qui intègre désormais Brooklyn et le Queens. Les deux héros doivent conjuguer leur vie privée chaotique avec l’émergence d’une milice sauvage menée par Kraven et l’apparition de la menace extraterrestre du Symbiote. Le titre pousse les capacités de déplacement à leur paroxysme grâce aux « delta-toiles » qui permettent de planer à toute vitesse entre les gratte-ciels en utilisant les couloirs de vent. Les combats gagnent en intensité avec l’apparition d’un système de parade indispensable et des arbres de compétences dédiés aux pouvoirs bio-électriques de Miles et aux bras mécaniques puis aux pouvoirs destructeurs du symbiote noir de Peter.', 8.9, 'Insomniac Games démontre une nouvelle fois son savoir-faire incontestable en matière de grand spectacle super-héroïque. Techniquement, le jeu utilise le SSD de la console de façon prodigieuse : les voyages rapides sont instantanés et le changement de personnage à la volée se fait en deux secondes chrono. La narration réussit à équilibrer le temps d’antenne des deux Spider-Man et livre une version de Venom terrifiante et jubilatoire. On regrette néanmoins que le titre prenne si peu de risques par rapport au premier opus, se reposant un peu trop sur une formule balisée. Certaines activités annexes sont très classiques (nettoyage de bases criminelles) et l’aventure principale se boucle un peu trop rapidement. Reste que le plaisir brut de voltige urbaine est totalement inégalé.', 'Se déplacer dans la ville reste un plaisir absolu. Le jeu est fun quasiment en permanence.', 'spider-man-2-banner-1780690133.jpg', 'spider-man-2-card-1780690133.jpg', '2026-05-02 15:43:58', 1),
(24, 'Persona 5 Royal', 'Vivez la double vie trépidante d’un lycéen tokyoïte le jour et d’un Voleur de Fantômes la nuit, prêt à réformer le cœur corrompu des adultes.', 'Persona 5 Royal est la version ultime du JRPG acclamé d’Atlus. Le joueur y incarne Joker, un lycéen injustement condamné à la liberté surveillée, qui fonde le groupe des Voleurs de Fantômes. Le gameplay est un mélange addictif divisé en deux pans. D’un côté, une simulation de vie sociale à Tokyo où il faut gérer son emploi du temps, étudier pour les examens, travailler à mi-temps et renforcer ses liens d’amitié (« Confidents »). De l’autre, de l’exploration de donjons psychologiques nés des désirs tordus des adultes (les Palaces), où l’on livre des combats tactiques au tour par tour hautement stylisés à l’aide d’entités psychiques appelées Personas, exploitant les faiblesses élémentaires des ennemis.', 9.4, 'Cette version « Royal » transcende un jeu qui était déjà un monument. L’ajout d’un trimestre scolaire supplémentaire, de nouveaux personnages capitaux (Kasumi et Maruki) et d’un donjon final magistral transfigurent l’intrigue en y apportant une nuance morale poignante. L’interface utilisateur et la direction artistique globale débordent d’un style urbain unique, chaque menu étant une œuvre d’art visuelle, le tout sublimé par une bande-son jazz/funk absolument inoubliable. On pourra éventuellement lui reprocher sa longueur colossale (comptez plus de 110 heures) et un démarrage très dirigiste qui peut rebuter les impatients. Mais pour quiconque accepte de s’investir, c’est une expérience émotionnelle d’une générosité folle et l’un des sommets absolus du JRPG de tous les temps.', 'Impossible de décrocher une fois lancé. Les musiques et les personnages restent mémorables.', 'persona-5-royal-banner-1780688122.jpg', 'persona-5-royal-card.jpg', '2026-05-17 14:56:39', 1),
(26, 'Resident Evil 4 Remake', 'Le retour triomphal d’un monument de l’action-horreur, magnifiquement recréé pour offrir une tension moderne et des combats d’une intensité viscérale.', 'Resident Evil 4 Remake redonne vie à l’aventure culte de 2005. L’agent spécial Leon S. Kennedy est envoyé dans un village isolé d’Europe pour secourir Ashley Graham, la fille du président des États-Unis, kidnappée par une secte mystérieuse appelée Los Illuminados. Le jeu reconstruit entièrement les décors avec le RE Engine pour instaurer une atmosphère beaucoup plus sombre, poisseuse et étouffante. Le gameplay modernise la maniabilité rigide de l’époque : Leon peut désormais marcher tout en visant, s’accroupir pour s’infiltrer et utiliser son couteau de combat pour parer les attaques de tronçonneuse ou effectuer des contres au timing serré, changeant drastiquement le rythme des vagues d’ennemis.', 9.2, 'Capcom réussit un véritable coup de maître en signant l’un des meilleurs remakes de l’histoire du jeu vidéo. L’équilibre trouvé entre la nostalgie respectueuse et la réinvention graphique et ludique est un modèle du genre. Le rythme est une leçon de game design : le titre ne laisse aucun répit, enchaînant des phases de défense oppressantes, des combats de boss dantesques et des énigmes environnementales mieux intégrées. La gestion de la mallette (l’inventaire) reste aussi addictive qu’autrefois. Si l’on note la suppression de quelques passages secondaires mineurs de l’original et une IA d’Ashley parfois un peu pénible à escorter dans les niveaux de difficulté élevés, le plaisir de jeu est total, viscéral et hautement rejouable.', 'J’ai adoré redécouvrir ce jeu dans cette version. L’atmosphère fonctionne parfaitement et les combats restent extrêmement satisfaisants.', 'resident-evil-4-remake-banner-1780687907.jpg', 'resident-evil-4-remake-card.jpg', '2026-05-17 14:59:03', 1),
(28, 'Death Stranding', 'Une œuvre d’auteur audacieuse et singulière où livrer des colis devient une odyssée métaphysique pour reconnecter une humanité brisée.', 'Death Stranding, né de l’esprit d’Hideo Kojima, projette le joueur dans un futur post-apocalyptique où un événement cataclysmique a brisé la frontière entre le monde des vivants et celui des morts. Des créatures invisibles (les Échoués) rôdent et une pluie accélérant le temps dégrade tout ce qu’elle touche. Le joueur incarne Sam Porter Bridges (incarné par Norman Reedus), un coursier chargé de parcourir d’ouest en est des États-Unis dévastés pour livrer des marchandises vitales et connecter les villes isolées à un réseau de communication. Le gameplay se focalise sur la topographie et la physique du déplacement : il faut gérer le poids du paquet, l’équilibre du héros, l’usure des bottes et surmonter le relief des montagnes.', 8.3, 'Death Stranding est un ovni vidéoludique courageux qui ose faire de la marche et de la logistique le cœur d’un triple-A d’action. La boucle de gameplay s’avère étonnamment gratifiante au fur et à mesure que l’on débloque des outils (exosquelettes, tyroliennes, routes) pour dompter ce terrain hostile. Le système de multijoueur asynchrone, où l’on découvre et utilise les structures bâties par d’autres joueurs dans notre propre monde, insuffle un sentiment de solidarité magnifique. Cependant, le jeu souffre des travers habituels de son créateur : une narration lourde, de trop longues cinématiques bavardes bourrées d’exposition redondante, et des combats de boss assez fades contre des masses de goudron. Un titre radical qui fascine autant qu’il peut profondément ennuyer.', 'Je comprends pourquoi certains détestent et d’autres adorent. Personnellement j’ai trouvé l’univers incroyable.', 'death-stranding-banner.jpg', 'death-stranding-card-1780688058.jpg', '2026-05-17 14:59:03', 1),
(29, 'Hades', 'Défiez le dieu des Enfers et frayez-vous un chemin sanglant à travers le royaume des morts dans un rogue-like divin au rythme effréné.', 'Hades met en scène Zagreus, le prince des Enfers et fils d’Hadès, bien décidé à s’enfuir du domaine de son père pour découvrir ses origines à la surface. Pour ce faire, il doit traverser quatre régions mythologiques générées de manière procédurale (le Tartare, l’Asphodèle, l’Élysée et le Styx). À chaque tentative d’évasion, les dieux de l’Olympe (Zeus, Athéna, Poséidon...) lui octroient des bienfaits divins qui modifient les attaques de ses six armes mythiques. Le gameplay est un action-RPG en vue isométrique d’une nervosité folle, combinant esquives millimétrées, attaques de zone et builds synergiques dévastateurs. La mort renvoie le joueur à la Maison d’Hadès, servant de hub central pour débloquer des améliorations permanentes.', 9.1, 'Supergiant Games a accompli l’exploit rarissime de réconcilier le grand public avec le genre souvent frustrant du rogue-like en intégrant la mort directement au sein de sa narration. Loin d’être un échec punitif, chaque trépas fait avancer l’histoire, développe les relations avec un casting de personnages mythologiques attachants et brillamment doublés, et débloque de savoureuses lignes de dialogue. La direction artistique en cell-shading est somptueuse et la boucle de jeu s’avère d’une efficacité addictive redoutable. On pourra chipoter sur le fait que l’on recroise souvent les mêmes boss majeurs au fil des dizaines de tentatives requises pour voir la véritable fin de l’histoire, mais la variété infinie des configurations d’armes et de bonus compense largement cette répétitivité.', 'J’ai été surpris par la profondeur du jeu. Même après plusieurs heures, j’avais encore envie de relancer une partie. Le système de progression est addictif et intelligent.', 'hades-banner-1780689847.jpg', 'hades-card-1780689847.jpg', '2026-05-17 14:00:00', 1),
(30, 'Baldur’s Gate 3', 'Le chef-d’œuvre absolu du RPG moderne, offrant une liberté narrative et tactique sans précédent basée sur les règles mythiques de Donjons & Dragons.', 'Baldur’s Gate 3 plonge le joueur dans les Royaumes Oubliés, alors qu’une invasion de Flagelleurs Mentaux menace le continent. Infecté par un parasite cérébral qui lui confère d’étranges pouvoirs, le joueur doit assembler un groupe de compagnons pour trouver un remède et déjouer un complot de grande envergure. Le jeu adapte avec une fidélité inouïe les règles de la 5e édition de Donjons & Dragons. Le gameplay propose une liberté d’action phénoménale : les dialogues ultra-ramifiés dépendent des classes et de l’historique, l’exploration récompense la verticalité et l’ingéniosité, et les combats tactiques au tour par tour reposent sur l’utilisation créative de l’environnement (pousser un ennemi d’une falaise, enflammer une flaque d\'huile).', 9.7, 'Larian Studios a accouché d’un jalon historique du jeu vidéo, un titre colossal qui redéfinit le genre du RPG occidental. Le degré d’écriture des compagnons (comme Astarion ou Ombrecœur) est exceptionnel, chacun bénéficiant d’un doublage magistral et d’une véritable capture de mouvement. La malléabilité du scénario donne le vertige : le jeu s’adapte à la moindre folie du joueur, acceptant le meurtre de personnages clés ou l’utilisation de tactiques imprévues sans jamais bloquer la progression. Ce monument souffre toutefois de sa propre complexité, pouvant effrayer les néophytes face à la masse d’informations à assimiler. On note également un troisième acte urbain un peu moins fluide techniquement et surchargé par rapport au rythme impeccable des deux premiers, mais l’ensemble est un chef-d’œuvre impérissable.', 'Chaque partie est différente. J’ai rarement vu un jeu où mes décisions avaient autant de conséquences. C’est un véritable bac à sable narratif.', 'baldur-s-gate-3-banner-1780689463.jpeg', 'baldur-s-gate-3-card-1780689463.jpg', '2026-05-17 14:05:00', 1),
(31, 'Starfield', 'Prenez votre envol vers les étoiles dans un space-opera à l’échelle gigantesque, mêlant exploration spatiale et quêtes intergalactiques.', 'Starfield est la première nouvelle licence de Bethesda Game Studios en 25 ans. En l’an 2330, l’humanité a colonisé le système solaire et au-delà. Le joueur incarne un mineur spatial qui intègre Constellation, le dernier groupe d’explorateurs de l’espace à la recherche d’artefacts mystérieux dispensés à travers la galaxie. Le gameplay propose la création complète d’un personnage, la construction et la personnalisation de ses propres vaisseaux spatiaux, le recrutement d’un équipage et l’exploration de plus de 1000 planètes. Les phases de jeu se partagent entre les combats terrestres à l’arme à feu, la récolte de ressources pour bâtir des avant-postes, et des batailles spatiales aux commandes de sa propre flotte.', 7.8, 'Starfield fascine par sa démesure et la solidité de sa formule « RPG Bethesda » bien rodée. Les quêtes de factions (notamment celle de la l’Union Coloniale ou de la Flotte Écarlate) sont remarquablement écrites et se révèlent bien plus passionnantes que la trame principale. Le système de construction de vaisseau est un jeu dans le jeu particulièrement chronophage et réussi. Néanmoins, l’immensité promise se heurte à des limites techniques frustrantes : le jeu est fragmenté par une multitude d’écrans de chargement cassant l’illusion du voyage spatial libre, et la génération procédurale des planètes crée trop de zones vides et de structures identiques d’un monde à l’autre. Le titre manque de la magie d’exploration organique d’un Skyrim, mais reste un très solide space-opera.', 'L’univers est fascinant mais inégal. Certaines planètes sont incroyables, d’autres beaucoup trop vides. Le potentiel est énorme mais pas totalement exploité.', 'starfield-banner-1780689336.jpg', 'starfield-card-1780689336.jpg', '2026-05-17 14:10:00', 1),
(32, 'Sekiro', 'Incarnez le Loup à un bras, un shinobi impitoyable pris au piège d’un Japon féodal sanglant où le sabre dicte sa loi avec une précision chirurgicale.', 'Sekiro: Shadows Die Twice délaisse les éléments RPG des précédents jeux FromSoftware pour livrer un jeu d’action-aventure pur. Le joueur y incarne le Loup, un shinobi armé d’une prothèse mécanique multifonctionnelle, chargé de protéger un jeune seigneur issu d’une lignée divine convoitée. Le titre se déroule durant l’ère de la fin de Sengoku réinventée avec du mysticisme japonais. Le gameplay introduit une verticalité folle grâce à un grappin et repose entièrement sur une mécanique inédite de « Posture ». Les combats abandonnent le principe d’esquive et de jauge d’endurance au profit d’un duel de sabre où parer les attaques ennemies au timing parfait permet de briser leur garde pour leur asséner un coup fatal.', 9.3, 'FromSoftware signe ici son système de combat le plus exigeant, mais aussi le plus grisant et le plus parfait sur le plan technique. Chaque affrontement majeur contre les boss ressemble à une danse mortelle frénétique, un choc d’acier mémorable où la moindre erreur d’inattention est immédiatement punitive. La courbe d’apprentissage est d’une rudesse absolue, le jeu n’offrant aucune possibilité de sur-monter la difficulté par le farming d’expérience ou l’appel à des alliés en ligne. C’est un titre qui exige que le joueur s’améliore lui-même. On peut regretter un certain recyclage de boss secondaires et de décors dans le dernier tiers du jeu, mais la satisfaction ressentie lors du clic final d’une parade réussie n’a aucun équivalent dans l’industrie.', 'J’ai rarement ressenti autant de satisfaction après avoir battu un boss. Le jeu demande de la patience mais récompense chaque effort.', 'sekiro-banner-1780689144.jpg', 'sekiro-card-1780689144.jpg', '2026-05-17 14:15:00', 1),
(33, 'Diablo IV', 'Le roi du Hack’n’Slash revient aux sources des ténèbres profonds pour vous proposer une traque sanglante de la terrible créatrice de Sanctuaire, Lilith.', 'Diablo IV marque le retour à l’esthétique gothique, sombre et poisseuse qui a forgé la réputation de la série. Après des siècles d’exil, Lilith, la fille de la Haine, a été invoquée dans le monde de Sanctuaire, propageant le chaos et le désespoir. Le joueur choisit parmi cinq classes de personnages hautement personnalisables (Barbare, Sorcier, Voleur, Nécromancien, Druide) et explore pour la première fois un immense monde ouvert partagé divisé en cinq régions. La boucle de gameplay traditionnelle est magnifiée : massacrer des hordes de démons, piller des donjons à l’atmosphère étouffante et optimiser continuellement son équipement via un système d’arbre de compétences et de tableaux de parangon poussés.', 8.1, 'Blizzard livre un titre à la direction artistique somptueuse et à l’ambiance sonore d’une noirceur remarquable, effaçant avec succès les reproches de colorimétrie trop vive faits à Diablo III. Les sensations d’impact en combat sont excellentes et la campagne principale s’avère agréable à suivre. Toutefois, la transition vers un modèle de type « jeu-service » avec un monde partagé apporte son lot de frustrations : connexion obligatoire permanente provoquant parfois des lags, un endgame (le contenu de fin de jeu) qui a mis du temps à se structurer au fil des saisons, et une répétitivité structurelle inhérente au genre qui s’installe assez vite. Cela reste une valeur refuge indéboulonnable et ultra-efficace pour les amateurs de loot.', 'Très bon jeu en coop. J’ai aimé l’ambiance plus sombre que Diablo III, même si le gameplay reste assez classique.', 'diablo-iv-banner-1780689076.jpg', 'diablo-iv-card-1780689027.jpg', '2026-05-17 14:20:00', 1),
(34, 'Minecraft', 'Le jeu phénoménal qui a repoussé les limites de l’imagination humaine, transformant un monde fait de cubes en un canevas infini de créativité.', 'Minecraft place le joueur au sein d’un monde infini entièrement généré de manière procédurale et modifiable bloc par bloc. Sans aucun didacticiel ni objectif scénaristique imposé, le titre se divise en deux modes principaux. Le mode Survie force le joueur à récolter des ressources basiques, à gérer sa faim, à se fabriquer des outils et des armes pour se défendre, la nuit tombée, contre des monstres (Zombies, Creepers). Le mode Créatif supprime toutes les contraintes de survie, offrant un accès illimité à l’intégralité des blocs du jeu et la capacité de voler, transformant le titre en un jeu de construction virtuel sans aucune limite de taille.', 9.5, 'Plus qu’un simple jeu vidéo, Minecraft est devenu en plus d’une décennie un véritable phénomène culturel intergénérationnel et un outil d’apprentissage. Derrière ses graphismes pixelisés simplistes se cache un système d’une profondeur inouïe, notamment grâce à la Redstone qui permet de concevoir de véritables circuits logiques et des machines automatisées complexes. La liberté offerte est vertigineuse et la rejouabilité est par essence infinie, surtout si l’on ajoute la richesse de sa communauté et ses milliers de mods. On peut regretter l’absence d’un guidage interne pour les recettes de craft complexes à l’ancienne, ou des combats un peu basiques, mais Minecraft reste le roi incontesté du bac à sable.', 'C’est un jeu auquel je reviens toujours. Il n’a pas vraiment d’objectif mais c’est justement ce qui le rend unique.', 'minecraft-banner.jpg', 'minecraft-card.jpg', '2026-05-17 14:25:00', 1),
(35, 'Fortnite', 'Le Battle Royale iconique devenu une immense plateforme culturelle mondiale, où la construction effrénée rencontre la pop-culture moderne.', 'Fortnite (dans son mode Battle Royale) parachute 100 joueurs simultanément sur une île colorée qui se rétrécit progressivement à cause d’une tempête mortelle. Le but est d’être le dernier vivant ou la dernière équipe en vie. La grande originalité du titre réside dans sa mécanique de destruction des décors pour récolter du bois, de la pierre et du métal afin de bâtir instantanément des structures (murs, rampes, toits) pour se protéger des tirs ennemis ou prendre de la hauteur. Le jeu s’est enrichi au fil des années d’un mode « Zéro Construction », mettant l’accent sur le tir traditionnel et la verticalité des déplacements.', 8.0, 'Epic Games a réussi un coup de génie marketing et technique en transformant un simple jeu de tir en un véritable carrefour de divertissement global et un métavers de la pop-culture (accueillant des concerts live virtuels de stars planétaires et des collaborations avec Marvel, Star Wars ou des animés). Le suivi du jeu est titanesque, proposant des changements de cartes radicaux et de nouvelles mécaniques chaque saison. Néanmoins, le mode de construction classique possède une courbe de progression aberrante qui crée un fossé gigantesque et frustrant entre les joueurs pros et les occasionnels. De plus, son modèle économique agressif basé sur les microtransactions de cosmétiques cible parfois de manière discutable les plus jeunes.', 'Très fun entre amis mais un peu compliqué à haut niveau. Les événements live sont impressionnants.', 'fortnite-banner-1780688600.jpg', 'fortnite-card-1780688722.jpg', '2026-05-17 14:30:00', 1),
(36, 'Counter-Strike 2', 'La renaissance technique du FPS compétitif absolu, aiguisant ses mécaniques légendaires sous un tout nouveau moteur graphique de pointe.', 'Counter-Strike 2 (CS2) est l’évolution majeure et gratuite de CS:GO, propulsée par le moteur Source 2. Le concept tactique intemporel reste inchangé : deux équipes de temps (les Terroristes et les Anti-Terroristes) s’affrontent dans des manches de deux minutes où l’objectif est d’amorcer/désamorcer une bombe ou d’éliminer l’équipe adverse. Le jeu se base sur une précision chirurgicale des tirs, une connaissance parfaite du recul des armes, et une gestion économique rigoureuse d’une manche à l’autre. CS2 apporte des nouveautés majeures comme des grenades fumigènes dynamiques et volumétriques qui réagissent désormais aux balles et aux explosions.', 8.8, 'Valve a réussi la mise à jour technique nécessaire pour faire entrer sa formule légendaire dans la modernité. Les nouvelles fumées dynamiques changent profondément la dimension tactique des lignes de vue et s’avèrent être une révolution de gameplay remarquable. Le jeu brille par son exigence compétitive intacte où la communication d’équipe et les réflexes purs priment. On déplore cependant un lancement qui s’est fait en amputant le titre de plusieurs modes de jeu appréciés de CS:GO (comme la Course aux armements initiale) et un système d’anti-triche (Valve Anti-Cheat) qui peine encore à endiguer efficacement la présence de tricheurs dans les parties avec classement, agaçant la communauté.', 'Un jeu toujours aussi stressant mais satisfaisant quand on progresse.', 'counter-strike-2-banner.jpg', 'counter-strike-2-card-1780688434.jpg', '2026-05-17 14:35:00', 1),
(37, 'League of Legends', 'Entrez dans l’arène du MOBA le plus disputé de la planète, un jeu de stratégie par équipe d’une profondeur absolue et impitoyable.', 'League of Legends (LoL) oppose deux équipes de cinq joueurs sur une carte symétrique appelée la Faille de l’Invocateur. Chaque joueur sélectionne un « Champion » parmi un roster de plus de 160 personnages possédant chacun des compétences uniques, un rôle défini (Top, Jungle, Mid, ADC, Support) et un style de jeu propre. L’objectif ultime est de détruire le Nexus ennemi situé au cœur de la base adverse. Pour y parvenir, les équipes doivent accumuler de l’or et de l’expérience en éliminant des sbires, en détruisant des tourelles défensives et en sécurisant des objectifs neutres majeurs (Dragons, Baron Nashor) demandant une coordination parfaite.', 8.6, 'League of Legends reste le roi incontesté de la scène e-sport mondiale grâce à un équilibrage stratégique d’une complexité inouïe, constamment renouvelé par des patchs bimensuels. Le sentiment de synergie et d’accomplissement lors d’un combat d’équipe parfaitement orchestré est d’une intensité rare. Le revers de la médaille est bien connu : la courbe de progression est une montagne infranchissable pour les débutants, le jeu expliquant très mal ses mécaniques complexes en interne. De plus, la toxicité légendaire et omniprésente de sa communauté en ligne au sein des parties compétitives peut ruiner l’expérience de jeu et dégoûter les joueurs en solo. Un monument incontournable, mais à consommer de préférence avec des amis.', 'Très addictif mais parfois frustrant. Chaque partie est différente.', 'league-of-legends-banner-1780688350.jpg', 'league-of-legends-card.jpg', '2026-05-17 14:40:00', 1),
(38, 'Hollow Knight', 'Explorez les ruines mélancoliques d’un royaume d’insectes déchu dans un Metroidvania indépendant d’une beauté poétique et d’une exigence rares.', 'Hollow Knight invite le joueur à descendre dans les profondeurs d’Hallownest, un immense royaume souterrain d’insectes en ruines, rongé par une étrange infection bulbeuse. Aux commandes d’un petit chevalier aphone armé d’un aiguillon, le joueur explore un dédale interconnecté de cavernes, de cités gothiques et de jardins fongiques. Le gameplay s’inscrit dans la pure tradition du Metroidvania : l’exploration est initialement limitée, et c’est en terrassant des boss ou en découvrant des secrets que l’on débloque des capacités de mouvement (double saut, dash mural) ouvrant de nouvelles voies. Les combats au corps à corps demandent des réflexes affûtés et une gestion précise de l\'Âme pour se soigner.', 9.4, 'Développé par une équipe minuscule de trois personnes (Team Cherry), Hollow Knight est un authentique chef-d’œuvre qui surpasse la majorité des productions majeures de l’industrie. La direction artistique entièrement dessinée à la main est d’une poésie visuelle renversante, portée par la bande-son magistrale et mélancolique de Christopher Larkin. Le level design est un modèle de perfection, laissant le joueur se perdre organiquement dans son univers sans jamais être frustré. Le challenge des combats est relevé, en particulier lors des extensions gratuites intégrées qui proposent des défis dantesques. Le seul micro-reproche réside dans un début d’aventure un peu lent, le temps de débloquer les premiers mouvements de course, mais l’expérience globale est inoubliable.', 'L’un des meilleurs jeux indépendants que j’ai joués. L’atmosphère est incroyable.', 'hollow-knight-banner-1780688246.jpg', 'hollow-knight-card-1780688246.jpg', '2026-05-17 14:45:00', 1);
